module multi_8bit (
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

reg [7:0] multiplicand;
reg [7:0] multiplier;
reg [15:0] partial_product;
reg [15:0] final_product;
integer i;

always @(*) begin
    multiplicand = A;
    multiplier = B;
    partial_product = 0;
    final_product = 0;
    for (i = 0; i < 8; i = i + 1) begin
        if (multiplier[i]) begin
            partial_product = partial_product + (multiplicand << i);
        end
    end
    product = partial_product;
end

endmodule
